fn solve(nums: Vec<i64>) -> i64 {
    let n = nums.len();
    let total_mask = 1 << n;
    if n == 0 {
        return 0;
    }

    let mut andB_arr = vec![0; total_mask];
    let mut dp_xor_arr = vec![0; total_mask];
    andB_arr[0] = 0;
    dp_xor_arr[0] = 0;

    for mask in 1..total_mask {
        let i = mask.trailing_zeros() as usize;
        let mask_without = mask ^ (1 << i);
        andB_arr[mask] = if mask_without == 0 {
            nums[i]
        } else {
            andB_arr[mask_without] & nums[i]
        };
        dp_xor_arr[mask] = if mask_without == 0 {
            nums[i]
        } else {
            dp_xor_arr[mask_without] ^ nums[i]
        };
    }

    let totalXOR = dp_xor_arr[total_mask - 1];
    let mut best = std::i64::MIN;

    for mask_B in 0..total_mask {
        let andB = andB_arr[mask_B];
        let xorB = dp_xor_arr[mask_B];
        let xorR = totalXOR ^ xorB;

        let mut R_list = Vec::with_capacity(n);
        for i in 0..n {
            if mask_B & (1 << i) == 0 {
                R_list.push(nums[i]);
            }
        }
        let k = R_list.len();
        if k == 0 {
            if andB > best {
                best = andB;
            }
            continue;
        }

        let mut current_xor = 0;
        let mut max_inner = andB + xorR;
        let mut current_gray = 0;
        for i in 1..(1 << k) {
            let next_gray = i ^ (i >> 1);
            let diff = current_gray ^ next_gray;
            let idx = diff.trailing_zeros() as usize;
            current_xor ^= R_list[idx];
            let candidate = andB + current_xor + (xorR ^ current_xor);
            if candidate > max_inner {
                max_inner = candidate;
            }
            current_gray = next_gray;
        }

        if max_inner > best {
            best = max_inner;
        }
    }

    best
}
