pub fn solve(nums: Vec<i64>) -> i64 {
    let n = nums.len();
    if n == 0 {
        return 0;
    }
    let k = (n + 1) / 2;
    let left = &nums[0..k];
    let right = &nums[k..n];

    fn compute_half(nums: &[i64]) -> Vec<(i64, bool, i64, i64)> {
        let mut states = vec![(0, false, 0, 0)];
        for &num in nums {
            let mut next_states = Vec::with_capacity(states.len() * 3);
            for state in &states {
                let (a, has_b, b, c) = *state;
                next_states.push((a ^ num, has_b, b, c));
                if has_b {
                    next_states.push((a, true, b & num, c));
                } else {
                    next_states.push((a, true, num, c));
                }
                next_states.push((a, has_b, b, c ^ num));
            }
            states = next_states;
        }
        states
    }

    let left_states = compute_half(left);
    let right_states = compute_half(right);

    let mut best = i64::MIN;
    for l in &left_states {
        for r in &right_states {
            let total_a = l.0 ^ r.0;
            let total_c = l.3 ^ r.3;
            let total_b = match (l.1, r.1) {
                (true, true) => l.2 & r.2,
                (true, false) => l.2,
                (false, true) => r.2,
                (false, false) => 0,
            };
            let candidate = total_a + total_b + total_c;
            if candidate > best {
                best = candidate;
            }
        }
    }

    best
}
